SELECT COUNT(*) AS TOTAL FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('apa') AND LOWER(SP.PAPEL) = LOWER('coordenador') AND LOWER(P.TIPO_PROJETO) = LOWER('pesquisa') AND LOWER(COALESCE(P.AREA_CONHECIMENTO, '')) LIKE '%quim%' AND P.DATA_INICIO >= (DATE('now', '-5 years'))